		private void Countdown_Callback( object state )
		{
			object[] states = (object[])state;
			int count = (int)states[0];
			CountdownCallback cb = (CountdownCallback)states[1];
			if ( count==0 )
			{
				if ( m_Countdown != null )
					m_Countdown.Stop();
				m_Countdown=null;
			}
			cb( count );
			states[0] = count - 1;
		}
