			selected = true;
			activeLineRect.position = Input.mousePosition;
			activeLineRect.localPosition = new Vector3 (activeLineRect.localPosition.x, 0.5f, 0f);
			activeLineRect.localScale = new Vector3 (0f, 1f, 1f);
