                    if (ExistingVenueDataRows.Length == 0)
                    {
                        ConferenceSetupTDSPcConferenceVenueRow AddedVenue = FMainDS.PcConferenceVenue.NewRowTyped(true);
                        AddedVenue.ConferenceKey = FPartnerKey;
